        <h2 className="text-xl font-bold mb-4">Notificar por WhatsApp</h2>
        <p className="mb-4">Se ha creado el registro correctamente. ¿Quieres enviar los detalles a {recipientName}?</p>
        <div className="mb-4 p-2 border rounded bg-gray-100 overflow-auto h-32">
          <p className="text-sm">{messagePreview}</p>
        </div>
        <div className="flex justify-end space-x-2">
          <button className="px-4 py-2 rounded bg-gray-300 hover:bg-gray-400" onClick={onClose}>
            Cerrar
          </button>
          <button className="px-4 py-2 rounded bg-green-500 text-white hover:bg-green-600" onClick={handleSend} disabled={isSending}>
